var e=()=>{let e=document.querySelector(`#menu-btn`),t=document.querySelector(`#close-menu`),n=document.querySelector(`#mobile-menu`),r=document.querySelector(`#overlay`);e.addEventListener(`click`,()=>{n.style.right=`0`,r.classList.remove(`opacity-0`,`invisible`),r.classList.add(`opacity-100`,`visible`)});let i=()=>{n.style.right=`-100%`,r.classList.remove(`opacity-100`,`visible`),r.classList.add(`opacity-0`,`invisible`)};t.addEventListener(`click`,i),r.addEventListener(`click`,i)};export{e as t};